#!/usr/bin/env python3
"""Compute PIP timeline compliance from workspace source documents.

Run from workspace root with no arguments. Prints JSON to stdout and exits 0.
"""

from __future__ import annotations

import json
import re
from datetime import date, datetime
from pathlib import Path


ROOT = Path(__file__).resolve().parents[1]
PIP_EMAIL_CHAIN = ROOT / "pip-email-chain.md"
POLICY_REFERENCE = ROOT / "labor-law-reference.md"
EMPLOYEE_HR_FILE = ROOT / "employee-hr-file.md"


def read_text(path: Path) -> str:
    return path.read_text(encoding="utf-8")


def parse_iso_date_from_pip_start(email_text: str) -> str:
    marker = "## 邮件 2: 绩效改进计划 (PIP) 启动"
    start = email_text.find(marker)
    if start == -1:
        raise ValueError("PIP start email section not found")
    section = email_text[start:]
    match = re.search(r"\*\*日期:\*\*\s*(\d{4}-\d{2}-\d{2})\s+\d{2}:\d{2}:\d{2}\s+CST", section)
    if not match:
        raise ValueError("PIP start date not found in start email")
    return match.group(1)


def parse_termination_effective_date(hr_text: str) -> str:
    match = re.search(r"\|\s*离职日期\s*\|\s*(\d{4}-\d{2}-\d{2})\s*\|", hr_text)
    if not match:
        raise ValueError("Termination effective date not found in HR file")
    return match.group(1)


def parse_policy_minimum_days(policy_text: str) -> int:
    patterns = [
        r"最低改进期限\s*\|\s*\*\*(\d+)天\*\*",
        r"PIP\).*?最低(\d+)天改进期限",
        r"PIP最低(\d+)天",
    ]
    for pattern in patterns:
        match = re.search(pattern, policy_text, flags=re.S)
        if match:
            return int(match.group(1))
    raise ValueError("Policy minimum PIP days not found")


def calculate_actual_days(start_date: str, end_date: str) -> int:
    start = date.fromisoformat(start_date)
    end = date.fromisoformat(end_date)
    return (end - start).days


def calculate_shortfall(policy_days: int, actual_days: int) -> int:
    return policy_days - actual_days


def is_compliant(actual_days: int, policy_days: int) -> bool:
    return actual_days >= policy_days


def extract_policy_citation(policy_text: str) -> str:
    # Use the company PIP policy table and Labor Contract Law Article 40 as the applicable basis.
    pip_requirement = "公司PIP政策：绩效改进计划最低改进期限为60天；检查节点每两周一次书面检查，需有邮件或会议记录；PIP结束后须有正式的最终评估文档；仅在PIP最终评估确认未达标后方可启动解雇流程。"
    article_40 = "《中华人民共和国劳动合同法》第四十条：劳动者不能胜任工作，经过培训或者调整工作岗位，仍不能胜任工作的，用人单位可依法处理；举证责任在用人单位。"
    # Keep citation text stable but verify the source contains the cited anchors.
    required_anchors = ["最低改进期限", "60天", "最终评估", "第四十条"]
    missing = [anchor for anchor in required_anchors if anchor not in policy_text]
    if missing:
        raise ValueError(f"Policy citation anchors missing: {missing}")
    return f"{pip_requirement} {article_40}"


def build_result() -> dict:
    email_text = read_text(PIP_EMAIL_CHAIN)
    policy_text = read_text(POLICY_REFERENCE)
    hr_text = read_text(EMPLOYEE_HR_FILE)

    pip_start_date = parse_iso_date_from_pip_start(email_text)
    termination_effective_date = parse_termination_effective_date(hr_text)
    policy_minimum_days = parse_policy_minimum_days(policy_text)
    actual_days = calculate_actual_days(pip_start_date, termination_effective_date)
    days_shortfall = calculate_shortfall(policy_minimum_days, actual_days)

    return {
        "pip_start_date": pip_start_date,
        "termination_effective_date": termination_effective_date,
        "policy_minimum_pip_days": policy_minimum_days,
        "actual_pip_days": actual_days,
        "days_shortfall": days_shortfall,
        "is_compliant": is_compliant(actual_days, policy_minimum_days),
        "applicable_policy_or_law": extract_policy_citation(policy_text),
        "source_files": {
            "pip_start_date": PIP_EMAIL_CHAIN.name,
            "termination_effective_date": EMPLOYEE_HR_FILE.name,
            "policy_minimum_pip_days": POLICY_REFERENCE.name,
            "applicable_policy_or_law": POLICY_REFERENCE.name,
        },
    }


def main() -> None:
    print(json.dumps(build_result(), ensure_ascii=False, indent=2))


if __name__ == "__main__":
    main()
PY
